export const hoverByLabel = buildHoverMap(allCompletionItems);

function buildHoverMap(items: LanguageItem[]): Map<string, LanguageItem> {
  const result = new Map<string, LanguageItem>();
  for (const entry of items) {
    result.set(entry.label, entry);
  }
  return result;
}

function item(label: string, detail: string, documentation: string, kind: CompletionItemKind): LanguageItem {
  return { label, detail, documentation, kind };
}
